import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface SessionBreakdown {
  session: string;
  focusTime: number;
}

interface PomodoroData {
  sessionStats: {
    completedSessions: number;
    totalFocusTimeMinutes: number;
    dailyGoalMinutes: number;
    progressPercentage: number;
  };
  sessionBreakdown: SessionBreakdown[];
}

export default function Widget() {
  const pomodoroData = response.data as PomodoroData;
  const { sessionStats, sessionBreakdown } = pomodoroData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722', mb: 1 }}>
              Pomodoro Progress
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Focus Time: {sessionStats.totalFocusTimeMinutes} minutes
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Completed Sessions: {sessionStats.completedSessions}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Daily Goal: {sessionStats.dailyGoalMinutes} minutes
            </Typography>
          </Box>

          <Box sx={{ width: '100%' }}>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#FF5722' }}>
                {sessionStats.progressPercentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={sessionStats.progressPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#FFE0B2',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FF5722',
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: sessionBreakdown.map(s => s.focusTime),
                color: '#FFC107',
              },
            ]}
            xAxis={[
              {
                data: sessionBreakdown.map(s => s.session),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
